export async function seedExpandedStates() {
  const existing = await db.select().from(counties);
  const existingNames = new Set(existing.map(c => `${c.name}|${c.stateCode}`));

  const newCounties = ALL_COUNTIES.filter(c => !existingNames.has(`${c.name}|${c.stateCode}`));
  if (newCounties.length === 0) {
    console.log("All counties already seeded.");
    return;
  }

  console.log(`Seeding ${newCounties.length} additional counties...`);
  const insertedCounties: { name: string; stateCode: string; id: number }[] = [];
  for (const county of newCounties) {
    const [inserted] = await db.insert(counties).values(county).returning();
    insertedCounties.push(inserted);
  }

  const allCountiesNow = await db.select().from(counties);
  const countyLookup = new Map<string, number>();
  allCountiesNow.forEach(c => countyLookup.set(`${c.name}|${c.stateCode}`, c.id));

  const existingDbs = await db.select().from(permitDatabases);
  const existingDbNames = new Set(existingDbs.map(d => d.name));

  const newDbs = ALL_DATABASES.filter(d => !existingDbNames.has(d.name));
  if (newDbs.length === 0) {
    console.log("All databases already seeded.");
    return;
  }

  console.log(`Seeding ${newDbs.length} additional databases...`);
  const dbRows = newDbs.map(d => {
    const countyId = countyLookup.get(`${d.countyName}|${d.stateCode}`);
    if (!countyId) {
      console.warn(`County not found for ${d.name}: ${d.countyName}, ${d.stateCode}`);
      return null;
    }
    return {
      name: d.name,
      jurisdiction: d.jurisdiction,
      jurisdictionType: d.jurisdictionType,
      countyId,
      portalUrl: d.portalUrl,
      searchUrl: d.searchUrl,
      platform: d.platform,
      phone: d.phone,
      email: d.email,
      address: d.address,
      searchableFields: ["address"] as string[],
      isActive: d.isActive,
      notes: d.notes,
    };
  }).filter(Boolean) as any[];

  if (dbRows.length > 0) {
    const batchSize = 50;
    for (let i = 0; i < dbRows.length; i += batchSize) {
      await db.insert(permitDatabases).values(dbRows.slice(i, i + batchSize));
    }
  }

  console.log(`Seeded ${insertedCounties.length} counties and ${dbRows.length} databases for all 50 states.`);
}
